package com.example.dataproc.grpc;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class DataTransferClient {
    public static void main(String[] args) throws InterruptedException {
        ManagedChannel channel = ManagedChannelBuilder
                .forAddress("localhost", 50051)
                .usePlaintext()
                .build();

        DataTransferServiceGrpc.DataTransferServiceStub stub = DataTransferServiceGrpc.newStub(channel);

        CountDownLatch uploadLatch = new CountDownLatch(1);

        StreamObserver<UploadResponse> uploadResponseObserver = new StreamObserver<>() {
            @Override
            public void onNext(UploadResponse value) {
                System.out.println("Uploaded fileId=" + value.getFileId() + " bytes=" + value.getTotalBytes());
            }

            @Override
            public void onError(Throwable t) {
                uploadLatch.countDown();
            }

            @Override
            public void onCompleted() {
                uploadLatch.countDown();
            }
        };

        StreamObserver<UploadRequest> uploadRequestObserver = stub.upload(uploadResponseObserver);
        uploadRequestObserver.onNext(UploadRequest.newBuilder()
                .setMetadata(FileMetadata.newBuilder()
                        .setFilename("sample.bin")
                        .setContentType("application/octet-stream")
                        .build())
                .build());

        byte[] sample = new byte[1024 * 1024];
        uploadRequestObserver.onNext(UploadRequest.newBuilder()
                .setChunk(com.google.protobuf.ByteString.copyFrom(sample))
                .build());
        uploadRequestObserver.onCompleted();

        uploadLatch.await(10, TimeUnit.SECONDS);

        CountDownLatch transferLatch = new CountDownLatch(1);

        StreamObserver<TransferMessage> transferResponseObserver = new StreamObserver<>() {
            @Override
            public void onNext(TransferMessage value) {
                System.out.println("Transfer ack session=" + value.getSessionId() + " attrs=" + value.getAttributesMap());
            }

            @Override
            public void onError(Throwable t) {
                transferLatch.countDown();
            }

            @Override
            public void onCompleted() {
                transferLatch.countDown();
            }
        };

        StreamObserver<TransferMessage> transferRequestObserver = stub.transfer(transferResponseObserver);
        transferRequestObserver.onNext(TransferMessage.newBuilder()
                .setSessionId("session-1")
                .setPayload(com.google.protobuf.ByteString.copyFrom(new byte[2 * 1024 * 1024]))
                .putAttributes("type", "data")
                .build());
        transferRequestObserver.onCompleted();

        transferLatch.await(10, TimeUnit.SECONDS);
        channel.shutdownNow().awaitTermination(5, TimeUnit.SECONDS);
    }
}

package com.example.dataproc.grpc;

import io.grpc.Grpc;
import io.grpc.InsecureServerCredentials;
import io.grpc.InsecureChannelCredentials;
import io.grpc.ManagedChannel;
import io.grpc.Server;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

public final class LargeMessageConfig {
    private LargeMessageConfig() {
    }

    public static Server buildServer(int port, DataTransferServer.DataTransferServiceImpl service) throws IOException {
        return Grpc.newServerBuilderForPort(port, InsecureServerCredentials.create())
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .addService(service)
                .build();
    }

    public static ManagedChannel buildChannel(String host, int port) {
        return Grpc.newChannelBuilderForAddress(host, port, InsecureChannelCredentials.create())
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();
    }

    public static void shutdown(Server server, ManagedChannel channel) throws InterruptedException {
        if (channel != null) {
            channel.shutdownNow().awaitTermination(5, TimeUnit.SECONDS);
        }
        if (server != null) {
            server.shutdownNow().awaitTermination();
        }
    }
}